SELECT sysItems.SEGMENT1 AS Assy, sysItems1.SEGMENT1 AS Compt, bomInv.IMPLEMENTATION_DATE, bomMat.ORGANIZATION_ID, tblOrgs.Org AS Unit, bomInv.DISABLE_DATE, Round(bomInv.COMPONENT_QUANTITY,5) AS Qty, IIf(Nz(bomInv.COMPONENT_QUANTITY,0)=0,Null,Round(1/bomInv.COMPONENT_QUANTITY,5)) AS Inverse_Qty, sysItems.DESCRIPTION AS assyDescription, sysItems.INVENTORY_ITEM_STATUS_CODE AS assyStatus, sysItems.ITEM_TYPE AS assyItemType, sysItems1.DESCRIPTION AS compDescription, sysItems1.INVENTORY_ITEM_STATUS_CODE AS compStatus, sysItems1.ITEM_TYPE AS compItemType, bomInv.COMPONENT_ITEM_ID AS COMPONENT_ITEM_ID, bomMat.ASSEMBLY_ITEM_ID AS ASSEMBLY_ITEM_ID
FROM (((APPS_BOM_BILL_OF_MATERIALS AS bomMat INNER JOIN APPS_BOM_INVENTORY_COMPONENTS AS bomInv ON bomMat.COMMON_BILL_SEQUENCE_ID = bomInv.BILL_SEQUENCE_ID) INNER JOIN INV_MTL_SYSTEM_ITEMS_B AS sysItems ON (bomMat.ORGANIZATION_ID = sysItems.ORGANIZATION_ID) AND (bomMat.ASSEMBLY_ITEM_ID = sysItems.INVENTORY_ITEM_ID)) INNER JOIN INV_MTL_SYSTEM_ITEMS_B AS sysItems1 ON (bomMat.ORGANIZATION_ID = sysItems1.ORGANIZATION_ID) AND (bomInv.COMPONENT_ITEM_ID = sysItems1.INVENTORY_ITEM_ID)) INNER JOIN tblOrgs ON bomMat.ORGANIZATION_ID = tblOrgs.ID
WHERE bomMat.ORGANIZATION_ID Not In (203,262)
    AND bomInv.DISABLE_DATE Is Null;

